// Accept lesson_id from parent workflow (W_Master) via Execute Workflow Trigger.
// Manual Trigger has no payload — lesson_id stays null and Code nodes downstream
// skip the lesson_id filter (operate on ALL segments — backward-compatible legacy behavior).
const incoming = $input.first()?.json || {};
const lesson_id = incoming.lesson_id || null;
return [{ json: { lesson_id } }];

// Batches tone analysis into chunks of TONE_BATCH so a long lesson (100+ segments)
// doesn't overflow a single Claude call or exceed max_tokens.
const TONE_BATCH = 40;
const lesson_id = $('Get Params').first().json.lesson_id;
let segments = $input.all()
  .filter(i => i.json.segment_id && i.json.en_text)
  .map(i => ({ segment_id: i.json.segment_id, en_text: i.json.en_text }));
if (lesson_id) segments = segments.filter(s => s.segment_id.startsWith(lesson_id + '_'));
if (segments.length === 0) throw new Error('No segments to analyze' + (lesson_id ? ' for lesson_id=' + lesson_id : ''));

// Externalized-prompts loader. Reads from the "prompts" Google Sheets tab via
// upstream Read Prompts node. Throws if a required key is missing (fail-fast).
// Placeholders use {{var}} syntax; vars object replaces them at load time.
const promptMap = {};
$('Read Prompts').all().forEach(i => { if (i.json.key) promptMap[i.json.key] = i.json.value; });
function loadPrompt(key, vars = {}) {
  const raw = promptMap[key];
  if (!raw) throw new Error(`Missing prompt "${key}" in prompts sheet — add a row with this key`);
  const result = Object.entries(vars).reduce(
    (s, [k, v]) => s.replace(new RegExp(`\\{\\{\\s*${k}\\s*\\}\\}`, 'g'), String(v ?? '')),
    raw
  );
  const leaks = result.match(/\{\{\s*[a-z][a-z0-9_]*\s*\}\}/g);
  if (leaks) throw new Error(`Unsubstituted placeholders in prompt "${key}": ${leaks.join(', ')}`);
  return result;
}
const sysPrompt = loadPrompt('tone_analysis_system');

const batches = [];
for (let i = 0; i < segments.length; i += TONE_BATCH) {
  batches.push(segments.slice(i, i + TONE_BATCH));
}

return batches.map(batch => ({
  json: {
    model: 'claude-sonnet-4-6',
    max_tokens: 4000,
    system: sysPrompt,
    messages: [{ role: 'user', content: 'Segments:\n\n' + JSON.stringify(batch, null, 2) }],
  },
}));

// Merges tone analysis from one or more batched Claude responses — emits per-segment items.
const merged = {};
for (const item of $input.all()) {
  try {
    let raw = item.json.content?.[0]?.text?.trim() || '{}';
    raw = raw.replace(/```json\n?/g, '').replace(/```\n?/g, '').trim();
    const match = raw.match(/\{[\s\S]*\}/);
    if (!match) { console.error('Parse Tone Map: no JSON in batch response'); continue; }
    const batchMap = JSON.parse(match[0]);
    Object.assign(merged, batchMap);
  } catch (e) {
    console.error('Parse Tone Map: parse failed for one batch:', e.message);
  }
}
if (Object.keys(merged).length === 0) throw new Error('Tone analysis returned empty results across all batches');
return Object.entries(merged).map(([segment_id, meta]) => ({
  json: { segment_id, segment_type: meta.segment_type || 'narrative', movement_keywords: meta.movement_keywords || '', key_concepts: meta.key_concepts || '' }
}));

// Batched translation: groups segments into batches of BATCH_SIZE and emits one Claude request per batch.
// This dramatically reduces Anthropic API request count (31 → 4 for a typical lesson) and stays under
// the default tier's output-tokens-per-minute ceiling (8K), which 1-segment-per-call hits at ~14 segments.
const lesson_id = $('Get Params').first().json.lesson_id;
const configItems = $('Read Config').all();
const configMap = {};
configItems.forEach(i => { if (i.json.key) configMap[i.json.key] = i.json.value; });
// Externalized-prompts loader. Reads from the "prompts" Google Sheets tab via
// upstream Read Prompts node. Throws if a required key is missing (fail-fast).
// Placeholders use {{var}} syntax; vars object replaces them at load time.
const promptMap = {};
$('Read Prompts').all().forEach(i => { if (i.json.key) promptMap[i.json.key] = i.json.value; });
function loadPrompt(key, vars = {}) {
  const raw = promptMap[key];
  if (!raw) throw new Error(`Missing prompt "${key}" in prompts sheet — add a row with this key`);
  const result = Object.entries(vars).reduce(
    (s, [k, v]) => s.replace(new RegExp(`\\{\\{\\s*${k}\\s*\\}\\}`, 'g'), String(v ?? '')),
    raw
  );
  const leaks = result.match(/\{\{\s*[a-z][a-z0-9_]*\s*\}\}/g);
  if (leaks) throw new Error(`Unsubstituted placeholders in prompt "${key}": ${leaks.join(', ')}`);
  return result;
}
const TOV = loadPrompt('tone_of_voice');

// active_langs gate — when set in config (e.g. "de" or "de,fr"), restricts W2
// to those langs only. Saves output tokens on Translate + skips Verify/Editor/
// Adapt work on the dropped langs. Empty/missing → all 7 (default behavior).
const ALL_LANGS = ['de', 'es', 'fr', 'pl', 'pt', 'it', 'tr'];
const activeRaw = (configMap.active_langs || '').trim();
const ACTIVE_LANGS = activeRaw
  ? activeRaw.split(',').map(s => s.trim().toLowerCase()).filter(l => ALL_LANGS.includes(l))
  : ALL_LANGS.slice();
const langsRestricted = ACTIVE_LANGS.length > 0 && ACTIVE_LANGS.length < ALL_LANGS.length;

const toneItems = $('Parse Tone Map').all();
const toneMap = {};
toneItems.forEach(i => { if (i.json.segment_id) toneMap[i.json.segment_id] = i.json; });

const BATCH_SIZE = 4;

const segments = $('Read Pending Segments').all()
  .filter(i => i.json.segment_id && i.json.en_text)
  .filter(i => !lesson_id || i.json.segment_id.startsWith(lesson_id + '_'));

const systemBlocks = [
  { type: 'text', text: loadPrompt('translate_system', { tov: TOV }), cache_control: { type: 'ephemeral' } },
];

const batches = [];
for (let i = 0; i < segments.length; i += BATCH_SIZE) {
  batches.push(segments.slice(i, i + BATCH_SIZE));
}

return batches.map((batch, bIdx) => {
  const userMap = {};
  const batchInfo = [];
  for (const s of batch) {
    const sid = s.json.segment_id;
    const enText = (s.json.en_text || '').replace(/"/g, "'");
    const tone = toneMap[sid] || {};
    userMap[sid] = { text: enText };
    if (tone.segment_type) userMap[sid].type = tone.segment_type;
    if (tone.key_concepts) userMap[sid].key_concepts = tone.key_concepts;
    batchInfo.push({ segment_id: sid, en_text: s.json.en_text, en_duration_sec: s.json.en_duration_sec });
  }
  // When active_langs is restricted, prepend an explicit instruction so Claude
  // emits only the requested lang keys instead of all 7 (cuts output tokens
  // ~85% on single-lang dry-runs). System prompt still permits the full set;
  // user-level override is sufficient and avoids touching the prompts sheet.
  const userJson = JSON.stringify(userMap, null, 2);
  const userContent = langsRestricted
    ? `IMPORTANT: For this batch, output translations ONLY for these language codes: ${ACTIVE_LANGS.join(', ')}. Omit all other languages from your JSON output.\n\n${userJson}`
    : userJson;
  return {
    json: {
      batch_index: bIdx,
      batch_size: batch.length,
      batch_segments: batchInfo,
      active_langs: ACTIVE_LANGS,
      claude_body: {
        model: 'claude-sonnet-4-6',
        max_tokens: 8000,
        system: systemBlocks,
        messages: [{ role: 'user', content: userContent }],
      },
    },
  };
});

// Parses batched Claude response → emits one item per segment.
// Each batch's Claude reply is a JSON object: { segment_id: { de, es, fr, pl, pt, it, tr }, ... }.
//
// R3.a: dropped segments (translator silently missed them).
// As of 2026-05-31: instead of immediately throwing, attempt auto-recovery by
// re-translating each dropped segment INDIVIDUALLY (one segment per Claude call,
// no prompt cache). Single-segment calls are effectively immune to silent-drop —
// Claude can't "forget" the only segment it was asked to translate. This makes W2
// resilient to the silent-drop pattern that bit us when Sonnet 4.6 occasionally
// drops 1 entire batch per run.
// As of 2026-06-05: recovery is now 5 tries (was 3) with longer backoff, and a
// final failure NO LONGER throws. Unrecovered segments are emitted with blank
// *_text and logged loudly. Rationale: a hard throw aborted the whole W2 run, and
// W_Master's retryOnFail then re-translated ALL 616 cells to recover one segment.
// Downstream verify/editor/adapt/formality all skip empty *_text, so a blank cell
// flows through harmlessly; W3 surfaces the gap (empty audio → needs_attention) and
// the operator sees the blank cells in the segments sheet to re-run W2/W_Regen for
// just those segments.
//
// active_langs gate: when set, REQUIRED_LANGS narrows to that subset so partial
// translator output is not flagged as "dropped" for inactive langs, and emitted
// items only carry *_text for active langs (autoMapInputData on Update Sheet
// then leaves inactive lang columns untouched in the segments sheet).
const ALL_LANGS = ['de', 'es', 'fr', 'pl', 'pt', 'it', 'tr'];
const configMap = {};
$('Read Config').all().forEach(i => { if (i.json.key) configMap[i.json.key] = i.json.value; });
const activeRaw = (configMap.active_langs || '').trim();
const REQUIRED_LANGS = activeRaw
  ? activeRaw.split(',').map(s => s.trim().toLowerCase()).filter(l => ALL_LANGS.includes(l))
  : ALL_LANGS.slice();
if (REQUIRED_LANGS.length === 0) throw new Error('active_langs filter produced empty lang list — check config');
const langsRestricted = REQUIRED_LANGS.length < ALL_LANGS.length;

const ANT_KEY = configMap.anthropic_api_key || '';

// Load translate_system prompt (same as Prepare and Expand) so the recovery
// retry uses identical instructions. Without this, a retry would skip the
// tone-of-voice + JSON-shape contract → output schema would drift.
const promptMap = {};
$('Read Prompts').all().forEach(i => { if (i.json.key) promptMap[i.json.key] = i.json.value; });
function loadPrompt(key, vars = {}) {
  const raw = promptMap[key];
  if (!raw) throw new Error(`Missing prompt "${key}" in prompts sheet — add a row with this key`);
  return Object.entries(vars).reduce(
    (s, [k, v]) => s.replace(new RegExp(`\\{\\{\\s*${k}\\s*\\}\\}`, 'g'), String(v ?? '')),
    raw
  );
}

const preparedItems = $('Prepare and Expand').all();
const claudeItems = $input.all();
const results = [];
const dropped = [];
const partial = [];

function parseClaudeBody(claudeResp) {
  try {
    let text = claudeResp.content?.[0]?.text?.trim() || '{}';
    text = text.replace(/```json\n?/g, '').replace(/```\n?/g, '').trim();
    const match = text.match(/\{[\s\S]*\}/);
    if (match) return JSON.parse(match[0]);
  } catch (e) {
    console.error(`Extract Translations: parse error: ${e.message}`);
  }
  return {};
}

for (let i = 0; i < claudeItems.length; i++) {
  const batchTranslations = parseClaudeBody(claudeItems[i].json);
  const batchSegments = preparedItems[i]?.json?.batch_segments || [];
  const batchIdx = preparedItems[i]?.json?.batch_index ?? i;

  for (const seg of batchSegments) {
    const translations = batchTranslations[seg.segment_id] || {};
    const filled = REQUIRED_LANGS.filter(l => translations[l] && translations[l].trim());
    if (filled.length === 0) {
      console.error(`Extract Translations: ${seg.segment_id} — empty/missing in batch ${batchIdx}.`);
      dropped.push(seg);
      continue;
    }
    if (filled.length < REQUIRED_LANGS.length) {
      const missing = REQUIRED_LANGS.filter(l => !filled.includes(l));
      console.warn(`Extract Translations: ${seg.segment_id} missing langs: ${missing.join(',')}`);
      partial.push({ segment_id: seg.segment_id, missing });
    }
    const out = {
      segment_id:      seg.segment_id,
      en_text:         seg.en_text || '',
      en_duration_sec: seg.en_duration_sec || 0,
    };
    for (const lang of REQUIRED_LANGS) out[`${lang}_text`] = translations[lang] || '';
    results.push({ json: out });
  }
}

// Auto-recovery for dropped segments. Single-segment Claude calls bypass the
// silent-drop failure mode: Claude cannot "forget" the only segment it was
// asked to translate. No prompt cache (fresh call per segment) avoids any
// cache-induced determinism the batch path may have hit.
async function sleep(ms) { return new Promise(r => setTimeout(r, ms)); }

async function retryOneSegment(seg) {
  const systemPrompt = loadPrompt('translate_system', { tov: loadPrompt('tone_of_voice') });
  const userMap = { [seg.segment_id]: { text: (seg.en_text || '').replace(/"/g, "'") } };
  const userJson = JSON.stringify(userMap, null, 2);
  const userContent = langsRestricted
    ? `IMPORTANT: For this batch, output translations ONLY for these language codes: ${REQUIRED_LANGS.join(', ')}. Omit all other languages from your JSON output.\n\n${userJson}`
    : userJson;

  const body = {
    model: 'claude-sonnet-4-6',
    max_tokens: 2000,
    system: [{ type: 'text', text: systemPrompt }],
    messages: [{ role: 'user', content: userContent }],
  };

  const MAX_TRIES = 5;
  for (let attempt = 0; attempt < MAX_TRIES; attempt++) {
    try {
      const resp = await this.helpers.httpRequest({
        method: 'POST',
        url: 'https://api.anthropic.com/v1/messages',
        headers: { 'x-api-key': ANT_KEY, 'anthropic-version': '2023-06-01', 'content-type': 'application/json' },
        body, json: true,
      });
      const parsed = parseClaudeBody(resp);
      const translations = parsed[seg.segment_id] || {};
      const filled = REQUIRED_LANGS.filter(l => translations[l] && translations[l].trim());
      if (filled.length > 0) return translations;
      console.warn(`Recovery for ${seg.segment_id} attempt ${attempt + 1}: still empty/missing`);
    } catch (e) {
      console.error(`Recovery for ${seg.segment_id} attempt ${attempt + 1} threw: ${e.message}`);
    }
    if (attempt < MAX_TRIES - 1) await sleep(2000 * Math.pow(2, attempt)); // 2s, 4s, 8s, 16s
  }
  return null;
}

// Emit a dropped segment with blank translations so the run continues. Verified
// downstream-safe: verify keeps original on empty, adapt/formality skip empty cells,
// Update Sheet auto-maps on segment_id. The blank cells are the operator's signal.
function emitBlank(seg) {
  const out = {
    segment_id:      seg.segment_id,
    en_text:         seg.en_text || '',
    en_duration_sec: seg.en_duration_sec || 0,
  };
  for (const lang of REQUIRED_LANGS) out[`${lang}_text`] = '';
  results.push({ json: out });
}

const stillDropped = [];
if (dropped.length > 0) {
  if (!ANT_KEY) {
    // No key → recovery impossible. Emit blanks rather than aborting the whole run.
    console.error(`Extract Translations: ${dropped.length} segment(s) dropped and anthropic_api_key missing from config — cannot auto-recover. Emitting blank translations: ${dropped.map(s => s.segment_id).join(', ')}`);
    for (const seg of dropped) { emitBlank(seg); stillDropped.push(seg.segment_id); }
  } else {
    console.log(`Extract Translations: ${dropped.length} dropped, attempting per-segment recovery`);
    for (const seg of dropped) {
      const translations = await retryOneSegment.call(this, seg);
      if (translations) {
        const out = {
          segment_id:      seg.segment_id,
          en_text:         seg.en_text || '',
          en_duration_sec: seg.en_duration_sec || 0,
        };
        for (const lang of REQUIRED_LANGS) out[`${lang}_text`] = translations[lang] || '';
        results.push({ json: out });
        console.log(`Recovered ${seg.segment_id}`);
      } else {
        emitBlank(seg);
        stillDropped.push(seg.segment_id);
      }
    }
  }
}

// Non-fatal: unrecovered drops are emitted blank (above) and logged loudly here so
// the operator can spot the blank cells in the segments sheet and re-run W2 / W_Regen
// for just those segments — instead of a hard throw that re-translates all 616 cells.
if (stillDropped.length > 0) {
  const partialNote = partial.length ? ` Partial (some langs missing): ${partial.map(p => p.segment_id + '(' + p.missing.join(',') + ')').join('; ')}.` : '';
  console.error(`⚠️ Extract Translations: ${stillDropped.length} segment(s) left BLANK after auto-recovery failed: ${stillDropped.join(', ')}. Review the blank cells and re-run W2.${partialNote}`);
}
return results;

// Verify Translations — QA pass on Sonnet's initial output.
// Batches segments (8 at a time), sends to Claude with anti-pattern rules.
// Applies corrections when Claude returns a different value; pass-through otherwise.
// QA_SYSTEM is sized ≥1024 tokens so cache_control: ephemeral activates on Sonnet 4.5.
const QA_BATCH_SIZE = 8;
const ALL_LANGS = ['de', 'es', 'fr', 'pl', 'pt', 'it', 'tr'];

const configMap = {};
$('Read Config').all().forEach(i => { if (i.json.key) configMap[i.json.key] = i.json.value; });
const apiKey = configMap.anthropic_api_key || '';
if (!apiKey) throw new Error('anthropic_api_key missing from config sheet');

// active_langs gate — narrow QA pass to active langs only. Inactive lang fields
// are not present in input items (extract_translations already filtered them).
const activeRaw = (configMap.active_langs || '').trim();
const LANGS = activeRaw
  ? activeRaw.split(',').map(s => s.trim().toLowerCase()).filter(l => ALL_LANGS.includes(l))
  : ALL_LANGS.slice();
if (LANGS.length === 0) throw new Error('active_langs filter produced empty lang list — check config');

// Externalized-prompts loader. Reads from the "prompts" Google Sheets tab via
// upstream Read Prompts node. Throws if a required key is missing (fail-fast).
// Placeholders use {{var}} syntax; vars object replaces them at load time.
const promptMap = {};
$('Read Prompts').all().forEach(i => { if (i.json.key) promptMap[i.json.key] = i.json.value; });
function loadPrompt(key, vars = {}) {
  const raw = promptMap[key];
  if (!raw) throw new Error(`Missing prompt "${key}" in prompts sheet — add a row with this key`);
  const result = Object.entries(vars).reduce(
    (s, [k, v]) => s.replace(new RegExp(`\\{\\{\\s*${k}\\s*\\}\\}`, 'g'), String(v ?? '')),
    raw
  );
  const leaks = result.match(/\{\{\s*[a-z][a-z0-9_]*\s*\}\}/g);
  if (leaks) throw new Error(`Unsubstituted placeholders in prompt "${key}": ${leaks.join(', ')}`);
  return result;
}
const QA_SYSTEM = loadPrompt('qa_verify_system');

async function sleep(ms) { return new Promise(r => setTimeout(r, ms)); }
async function callQA(body) {
  const MAX_TRIES = 4;
  for (let attempt = 0; attempt < MAX_TRIES; attempt++) {
    try {
      const resp = await this.helpers.httpRequest({
        method: 'POST',
        url: 'https://api.anthropic.com/v1/messages',
        headers: { 'x-api-key': apiKey, 'anthropic-version': '2023-06-01', 'content-type': 'application/json' },
        body, json: true,
      });
      return resp.content?.[0]?.text?.trim() || '';
    } catch (e) {
      if (attempt === MAX_TRIES - 1) { console.error('Verify Translations QA failed after retries:', e.message); return ''; }
      await sleep(2000 * Math.pow(2, attempt));
    }
  }
  return '';
}

const items = $input.all();
const batches = [];
for (let i = 0; i < items.length; i += QA_BATCH_SIZE) batches.push(items.slice(i, i + QA_BATCH_SIZE));

// Bounded-concurrent batch processing: process CHUNK batches in parallel via
// Promise.all, sequential between chunks. Avoids n8n's 300s task-runner timeout
// on big lessons while keeping concurrency within Anthropic Tier 1 rate limits.
// Cap=3: existing exponential backoff in callQA absorbs any 429s gracefully.
const CHUNK = parseFloat(configMap.w2_llm_chunk) || 6;
const corrections = {};
async function runOneVerifyBatch(batch) {
  const userMap = {};
  for (const it of batch) {
    const j = it.json;
    const entry = { en: j.en_text || '' };
    for (const lang of LANGS) entry[lang] = j[`${lang}_text`] || '';
    userMap[j.segment_id] = entry;
  }
  const body = {
    model: 'claude-sonnet-4-6',
    max_tokens: 8000,
    system: [{ type: 'text', text: QA_SYSTEM, cache_control: { type: 'ephemeral' } }],
    messages: [{ role: 'user', content: JSON.stringify(userMap, null, 2) }],
  };
  const raw = await callQA.call(this, body);
  try {
    const cleaned = raw.replace(/```json\n?/g, '').replace(/```\n?/g, '').trim();
    const match = cleaned.match(/\{[\s\S]*\}/);
    if (match) return JSON.parse(match[0]);
  } catch (e) { console.error('Verify Translations parse error:', e.message); }
  return {};
}
for (let i = 0; i < batches.length; i += CHUNK) {
  const slice = batches.slice(i, i + CHUNK);
  const partial = await Promise.all(slice.map(b => runOneVerifyBatch.call(this, b)));
  for (const p of partial) Object.assign(corrections, p);
}

// Apply corrections: if QA returned a value for a lang, use it; else keep original.
return items.map(it => {
  const sid = it.json.segment_id;
  const corr = corrections[sid] || {};
  const out = { ...it.json };
  for (const lang of LANGS) {
    const key = `${lang}_text`;
    if (corr[lang] && corr[lang].trim()) out[key] = corr[lang].trim();
  }
  return { json: out };
});

// Gemini Editor — cross-model second-pass review on Sonnet's QA-corrected output.
// Same input/output schema as Verify Translations (drop-in compatible). Reads
// gemini_api_key from config sheet. Calls Gemini 3.5 Flash via OpenAI-compatible endpoint with
// retries with exponential backoff (4 attempts: 2s/4s/8s). On final failure,
// returns empty corrections → all items pass through with Verify-cleaned text.
//
// EDITOR_SYSTEM is sized ≥1024 tokens so Gemini's prompt cache (when prefix ≥ threshold) activates
// on batches 2-4 (no explicit cache_control needed — Google handles shared
// system-prompt prefixes).
const QA_BATCH_SIZE = 8;
const ALL_LANGS = ['de', 'es', 'fr', 'pl', 'pt', 'it', 'tr'];

const configMap = {};
$('Read Config').all().forEach(i => { if (i.json.key) configMap[i.json.key] = i.json.value; });
const apiKey = configMap.gemini_api_key || '';
if (!apiKey) throw new Error('gemini_api_key missing from config sheet');

// active_langs gate — narrow editor pass to active langs only. Inactive lang
// fields are not in input items (extract_translations already filtered), so we
// just align LANGS here for the userMap build + apply loop.
const activeRaw = (configMap.active_langs || '').trim();
const LANGS = activeRaw
  ? activeRaw.split(',').map(s => s.trim().toLowerCase()).filter(l => ALL_LANGS.includes(l))
  : ALL_LANGS.slice();
if (LANGS.length === 0) throw new Error('active_langs filter produced empty lang list — check config');

// Externalized-prompts loader. Reads from the "prompts" Google Sheets tab via
// upstream Read Prompts node. Throws if a required key is missing (fail-fast).
// Placeholders use {{var}} syntax; vars object replaces them at load time.
const promptMap = {};
$('Read Prompts').all().forEach(i => { if (i.json.key) promptMap[i.json.key] = i.json.value; });
function loadPrompt(key, vars = {}) {
  const raw = promptMap[key];
  if (!raw) throw new Error(`Missing prompt "${key}" in prompts sheet — add a row with this key`);
  const result = Object.entries(vars).reduce(
    (s, [k, v]) => s.replace(new RegExp(`\\{\\{\\s*${k}\\s*\\}\\}`, 'g'), String(v ?? '')),
    raw
  );
  const leaks = result.match(/\{\{\s*[a-z][a-z0-9_]*\s*\}\}/g);
  if (leaks) throw new Error(`Unsubstituted placeholders in prompt "${key}": ${leaks.join(', ')}`);
  return result;
}
const EDITOR_SYSTEM = loadPrompt('editor_system');

async function sleep(ms) { return new Promise(r => setTimeout(r, ms)); }
async function callGemini(body) {
  const MAX_TRIES = 4;
  for (let attempt = 0; attempt < MAX_TRIES; attempt++) {
    try {
      const resp = await this.helpers.httpRequest({
        method: 'POST',
        url: 'https://generativelanguage.googleapis.com/v1beta/openai/chat/completions',
        headers: { 'Authorization': `Bearer ${apiKey}`, 'content-type': 'application/json' },
        body, json: true,
      });
